const today = new Date().toISOString().slice(0, 10);
const stamp = Date.now();
const runId = `N8N-STOCK-SERIAL-${stamp}`;
return [{ json: { runId, company: 'Thái Duy Digital', parentWarehouse: 'All Warehouses - TDD', postingDate: today, itemGroup: `${runId} Nhóm serial`, warehouseName: `${runId} Serial WH`, itemCode: `${runId} Hàng serial Đặc biệt`, serialA: `${runId}-SN-001`, serialB: `${runId}-SN-002`, receiptQty: 2, issueQty: 1, rate: 53 } }];

const ctx = $node['Build Serial Context'].json;
const receipt = $node['Submit Serial Receipt'].json;
const issue = $node['Submit Serial Issue'].json;
const bin = $('Verify Serial Bin').all().map(i => i.json);
const sle = $('Verify Serial SLE').all().map(i => i.json);
const expectedQty = ctx.receiptQty - ctx.issueQty;
const text = JSON.stringify({ ctx, receipt, issue, bin, sle });
const securityFindings = ['api key', 'api_secret', 'authorization', 'token ', 'password'].filter(term => text.toLowerCase().includes(term));
const hasReceiptLedger = sle.some(row => row.voucher_no === $node['Create Serial Receipt'].json.name && Number(row.actual_qty) === ctx.receiptQty);
const hasIssueLedger = sle.some(row => row.voucher_no === $node['Create Serial Issue'].json.name && Number(row.actual_qty) === -ctx.issueQty && Number(row.qty_after_transaction) === expectedQty);
const status = Number(receipt.docstatus) === 1 && Number(issue.docstatus) === 1 && Number(bin[0]?.actual_qty) === expectedQty && hasReceiptLedger && hasIssueLedger ? 'passed' : 'failed';
return [{ json: { status, runId: ctx.runId, item: $node['Create Serial Item'].json.name, serialReceived: [ctx.serialA, ctx.serialB], serialIssued: ctx.serialA, warehouse: $node['Create Serial Warehouse'].json.name, receipt: $node['Create Serial Receipt'].json.name, receiptDocstatus: receipt.docstatus, issue: $node['Create Serial Issue'].json.name, issueDocstatus: issue.docstatus, binActualQty: bin[0]?.actual_qty, serialLedgerRows: sle.length, serialLedgerActualQty: sle.map(row => ({ voucher_no: row.voucher_no, actual_qty: row.actual_qty, qty_after_transaction: row.qty_after_transaction })), serialTrackingNote: 'ERPNext v16 stores serial detail in Serial and Batch Bundle/Entry; DB verification records exact serial_no rows.', securityFindings } }];
